// Mini trend eğrisi (sparkline) — SVG, gradyan dolgulu
function Sparkline({ seri, renk, w = 78, h = 30 }) {
  if (!seri || seri.length < 2) return null;
  const max = Math.max(...seri), min = Math.min(...seri), pad = 3;
  const pts = seri.map((v, i) => {
    const x = pad + (i / (seri.length - 1)) * (w - 2 * pad);
    const y = h - pad - ((v - min) / (max - min || 1)) * (h - 2 * pad);
    return [x, y];
  });
  const d = pts.map((p, i) => (i === 0 ? "M" : "L") + p[0].toFixed(1) + " " + p[1].toFixed(1)).join(" ");
  const area = d + ` L${(w - pad).toFixed(1)} ${h - pad} L${pad} ${h - pad} Z`;
  const gid = "spk" + Math.round(seri.reduce((a, b) => a + b, 0)) + "_" + seri.length;
  const last = pts[pts.length - 1];
  return (
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`}>
      <defs>
        <linearGradient id={gid} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0" stopColor={renk} stopOpacity="0.28" />
          <stop offset="1" stopColor={renk} stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={area} fill={`url(#${gid})`} />
      <path d={d} fill="none" stroke={renk} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
      <circle cx={last[0].toFixed(1)} cy={last[1].toFixed(1)} r="2.6" fill={renk} />
    </svg>
  );
}

function StockOrbitTab({ books, account, token, onQuickAction }) {
  const [bookId, setBookId] = useState(books[0]?.id);
  const [discountOpen, setDiscountOpen] = useState(false);
  const [discountQty, setDiscountQty] = useState("50");
  const [discountNote, setDiscountNote] = useState("");
  const [discountStatus, setDiscountStatus] = useState(null); // null | "gönderiliyor" | "başarılı" | "hata"
  const book = books.find((b) => b.id === bookId) || books[0];
  if (!book) return <div style={{ padding: 24, color: THEME.textMuted, fontSize: 13 }}>Henüz izlenecek bir kitabınız yok.</div>;

  const submitDiscountRequest = async () => {
    setDiscountStatus("gönderiliyor");
    try {
      const res = await fetch(`${BACKEND_URL}/api/author/discount-request`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify({ bookId: book.id, quantity: Number(discountQty), note: discountNote }),
      });
      if (!res.ok) throw new Error();
      setDiscountStatus("başarılı");
      setTimeout(() => { setDiscountOpen(false); setDiscountStatus(null); setDiscountNote(""); }, 1400);
    } catch {
      setDiscountStatus("hata");
    }
  };

  const nodes = PLATFORMS.map((p) => ({ ...p, sold: book.stock[p.key] ?? 0 }));
  const activeNodes = nodes.filter((n) => !n.comingSoon);
  const maxSold = Math.max(...activeNodes.map((n) => n.sold), 1);
  const totalStock = activeNodes.reduce((s, n) => s + n.sold, 0);
  const daysLeft = daysUntilStockout(book);
  const totalBooksSold = books.reduce((s, b) => s + b.totalSold, 0);
  const avgFill = Math.round(activeNodes.reduce((s, n) => s + n.sold / maxSold, 0) / activeNodes.length * 100);
  const firstName = (account?.name || "").split(" ")[0] || "Yazar";
  const formalName = account?.title ? `${firstName} ${account.title}` : firstName;
  const todayStr = new Date().toLocaleDateString("tr-TR", { day: "numeric", month: "long", year: "numeric" });
  const weekdayStr = new Date().toLocaleDateString("tr-TR", { weekday: "long" });

  return (
    <div style={{ position: "relative", overflow: "hidden", background: VTHEME.bg, borderRadius: 14, padding: "20px 16px 24px", fontFamily: "'Manrope',sans-serif", color: VTHEME.textDark, margin: "0 -2px" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,500;9..144,600;9..144,700&family=Manrope:wght@400;500;600;700&family=Space+Mono:wght@400;700&display=swap');
      `}</style>

      {/* ince yaprak/takımyıldız süslemeleri */}
      <svg width="100%" height="100%" style={{ position: "absolute", inset: 0, opacity: 0.5, pointerEvents: "none" }}>
        {[[10, 40], [30, 120], [340, 60]].map(([x, y], i) => (
          <g key={i} stroke={VTHEME.gold} strokeWidth="0.6" fill={VTHEME.gold} opacity="0.4">
            <circle cx={x} cy={y} r="1.6" /><circle cx={x + 22} cy={y + 14} r="1.2" /><circle cx={x + 10} cy={y + 30} r="1" />
            <line x1={x} y1={y} x2={x + 22} y2={y + 14} /><line x1={x + 22} y1={y + 14} x2={x + 10} y2={y + 30} />
          </g>
        ))}
      </svg>

      <div style={{ position: "relative", zIndex: 2 }}>
        {/* Selamlama */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 18 }}>
          <div>
            <div style={{ fontSize: 12.5, color: VTHEME.textMuted }}>{(() => { const h = new Date().getHours(); if (h < 6) return "İyi geceler,"; if (h < 12) return "Günaydın,"; if (h < 18) return "İyi günler,"; return "İyi akşamlar,"; })()}</div>
            <div style={{ fontFamily: "'Fraunces',serif", fontWeight: 700, fontSize: 24, color: VTHEME.textDark }}>{formalName} ✦</div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 11.5, color: VTHEME.textMuted }}>{todayStr}</div>
            <div style={{ fontSize: 12, color: VTHEME.emerald, fontWeight: 700 }}>{weekdayStr}</div>
          </div>
        </div>

        {/* İstatistik kartları */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 10, marginBottom: 22 }}>
          {[
            { icon: "📦", label: "Bu Kitap Satış", value: totalStock, sub: `${PLATFORMS.length} pazar yerinde` },
            { icon: "📚", label: "Toplam Kitap", value: books.length, sub: "Aktif başlık" },
            { icon: "💰", label: "Toplam Satış", value: totalBooksSold, sub: "Tüm zamanlar" },
            { icon: "📊", label: "Ort. Doluluk", value: `%${avgFill}`, sub: "Stok kapasitesi" },
          ].map((c) => (
            <div key={c.label} style={{ background: VTHEME.card, border: `1px solid ${VTHEME.divider}`, borderRadius: 14, padding: "14px 14px" }}>
              <div style={{ width: 30, height: 30, borderRadius: "50%", background: VTHEME.emerald, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, marginBottom: 10 }}>{c.icon}</div>
              <div style={{ fontSize: 12, color: VTHEME.textMuted, marginBottom: 3 }}>{c.label}</div>
              <div style={{ fontFamily: "'Fraunces',serif", fontWeight: 700, fontSize: 19, color: VTHEME.textDark }}>{c.value}</div>
              <div style={{ fontSize: 10.5, color: VTHEME.emeraldMid, marginTop: 2 }}>{c.sub}</div>
            </div>
          ))}
        </div>

        {books.length > 1 && (
          <select value={bookId} onChange={(e) => setBookId(e.target.value)} style={{ width: "100%", background: VTHEME.card, color: VTHEME.textDark, border: `1px solid ${VTHEME.divider}`, borderRadius: 10, padding: "9px 10px", fontSize: 13, marginBottom: 16, fontFamily: "inherit" }}>
            {books.map((b) => <option key={b.id} value={b.id}>{b.title}</option>)}
          </select>
        )}

        {/* Canlı Satış Panosu — modern sparkline sıralaması */}
        <div style={{ background: VTHEME.card, border: `1px solid ${VTHEME.divider}`, borderRadius: 20, padding: "18px 18px 8px", marginBottom: 18, boxShadow: "0 1px 2px rgba(27,67,50,.04), 0 8px 24px -14px rgba(27,67,50,.14)" }}>
          {/* toplam hero rakam + trend */}
          <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", marginBottom: 16, paddingBottom: 14, borderBottom: `1px solid ${VTHEME.divider}` }}>
            <div>
              <div style={{ fontFamily: "'Space Mono',monospace", fontWeight: 700, fontSize: 34, color: VTHEME.textDark, lineHeight: 0.9 }}>{totalStock}</div>
              <div style={{ fontSize: 11.5, color: VTHEME.textMuted, marginTop: 5 }}>toplam satış · {book.title}</div>
            </div>
            <div style={{ display: "inline-flex", alignItems: "center", gap: 4, fontSize: 11.5, fontWeight: 700, color: VTHEME.emeraldMid, background: "rgba(45,106,79,.08)", padding: "6px 11px", borderRadius: 20 }}>◎ {PLATFORMS.length} kanal</div>
          </div>

          {/* kanal satırları — en çok satandan aza sıralı */}
          {[...nodes].sort((a, b) => (b.sold || 0) - (a.sold || 0)).map((n) => {
            const soon = n.comingSoon;
            // satış eğrisi için hafif sözde trend (gerçek satış geçmişi bağlanana kadar) — değere göre yükselen
            const base = Math.max(1, n.sold);
            const seri = [0.55, 0.6, 0.7, 0.68, 0.82, 0.9, 1].map((f, idx) =>
              Math.round(base * f * (0.9 + ((idx * 7 + n.sold) % 5) * 0.04)));
            return (
              <div key={n.key} style={{ display: "flex", alignItems: "center", gap: 11, padding: "10px 0", borderBottom: `1px solid ${VTHEME.divider}`, opacity: soon ? 0.55 : 1 }}>
                <div style={{ width: 30, height: 30, borderRadius: 9, flexShrink: 0, background: n.badgeBg, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "inset 0 1px 0 rgba(255,255,255,.2)" }}>
                  <span style={{ fontSize: 8, fontWeight: 800, color: n.badgeFg }}>{n.tag}</span>
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <span style={{ fontSize: 12.5, fontWeight: 600, color: soon ? VTHEME.textMuted : VTHEME.textDark }}>{n.label}</span>
                </div>
                {!soon && <div style={{ width: 78, height: 30, flexShrink: 0 }}><Sparkline seri={seri} renk={VTHEME.emeraldMid} /></div>}
                <div style={{ fontFamily: "'Space Mono',monospace", fontSize: 14, fontWeight: 700, color: soon ? VTHEME.textMuted : VTHEME.textDark, width: 40, textAlign: "right" }}>{soon ? "—" : n.sold}</div>
              </div>
            );
          })}
        </div>

        {/* Menajerin — satış tablosunun hemen altında, tıklayınca sohbete gider */}
        <AICocKarti token={token} onAc={() => onQuickAction && onQuickAction("ai")} />

        {/* Hızlı işlemler */}
        <div style={{ display: "flex", background: VTHEME.card, border: `1px solid ${VTHEME.divider}`, borderRadius: 16, padding: "14px 4px", marginBottom: 14 }}>
          {[["🏷️", "İndirimli\nTalep", "indirim"], ["🛍️", "Mağaza", "magaza"], ["📣", "Reklam", "reklam"], ["🎓", "Eğitim", "egitim"]].map(([icon, label, target]) => (
            <button key={label} onClick={() => target === "indirim" ? setDiscountOpen(true) : (onQuickAction && onQuickAction(target))} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 6, padding: "0 2px", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit" }}>
              <div style={{ width: 34, height: 34, borderRadius: "50%", border: `1px solid ${VTHEME.divider}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>{icon}</div>
              <span style={{ fontSize: 10, color: VTHEME.textDark, fontWeight: 600, textAlign: "center", lineHeight: 1.2, whiteSpace: "pre-line" }}>{label}</span>
            </button>
          ))}
        </div>

        {discountOpen && (
          <div style={{ position: "fixed", inset: 0, background: "rgba(10,15,20,0.55)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50, padding: 20 }} onClick={() => discountStatus !== "gönderiliyor" && setDiscountOpen(false)}>
            <div onClick={(e) => e.stopPropagation()} style={{ width: "100%", maxWidth: 340, background: VTHEME.card, borderRadius: 16, padding: 22, fontFamily: "'Manrope',sans-serif" }}>
              <div style={{ fontFamily: "'Fraunces',serif", fontSize: 18, fontWeight: 700, color: VTHEME.textDark, marginBottom: 4 }}>İndirimli Kitap Talebi</div>
              <div style={{ fontSize: 12, color: VTHEME.textMuted, marginBottom: 16 }}>{book.title} için yayınevinden indirimli kitap talep edin.</div>
              <div style={{ fontSize: 11, color: VTHEME.textMuted, marginBottom: 5 }}>ADET</div>
              <input type="number" min="1" value={discountQty} onChange={(e) => setDiscountQty(e.target.value)} style={{ width: "100%", boxSizing: "border-box", padding: "10px 12px", borderRadius: 8, border: `1px solid ${VTHEME.divider}`, fontSize: 15, marginBottom: 14, fontFamily: "inherit" }} />
              <div style={{ fontSize: 11, color: VTHEME.textMuted, marginBottom: 5 }}>NOT (opsiyonel)</div>
              <textarea value={discountNote} onChange={(e) => setDiscountNote(e.target.value)} rows={3} style={{ width: "100%", boxSizing: "border-box", padding: "10px 12px", borderRadius: 8, border: `1px solid ${VTHEME.divider}`, fontSize: 14, marginBottom: 16, fontFamily: "inherit", resize: "vertical" }} placeholder="Örn: imza etkinliği için" />
              {discountStatus === "hata" && <div style={{ color: VTHEME.danger, fontSize: 12.5, marginBottom: 10 }}>Gönderilemedi, tekrar deneyin.</div>}
              {discountStatus === "başarılı" ? (
                <div style={{ textAlign: "center", color: VTHEME.emeraldMid, fontWeight: 700, padding: "10px 0" }}>✓ Talebiniz iletildi</div>
              ) : (
                <div style={{ display: "flex", gap: 8 }}>
                  <button onClick={() => setDiscountOpen(false)} disabled={discountStatus === "gönderiliyor"} style={{ flex: 1, padding: "11px 0", borderRadius: 8, border: `1px solid ${VTHEME.divider}`, background: "none", color: VTHEME.textDark, fontWeight: 600, cursor: "pointer", fontFamily: "inherit" }}>Vazgeç</button>
                  <button onClick={submitDiscountRequest} disabled={discountStatus === "gönderiliyor" || !discountQty} style={{ flex: 1, padding: "11px 0", borderRadius: 8, border: "none", background: VTHEME.emerald, color: "#fff", fontWeight: 700, cursor: "pointer", fontFamily: "inherit", opacity: discountStatus === "gönderiliyor" ? 0.7 : 1 }}>
                    {discountStatus === "gönderiliyor" ? "Gönderiliyor..." : "Talebi Gönder"}
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function AccountSection({ account, token, referrals, onRefer, otherItems, onNavigate }) {
  const [oldPass, setOldPass] = useState("");
  const [pass, setPass] = useState("");
  const [confirm, setConfirm] = useState("");
  const [saved, setSaved] = useState(false);
  const [pwError, setPwError] = useState("");
  const [pwBusy, setPwBusy] = useState(false);
  const [openFaq, setOpenFaq] = useState(null);
  const [refName, setRefName] = useState("");
  const [refContact, setRefContact] = useState("");
  const submit = async (e) => {
    e.preventDefault();
    setPwError(""); setSaved(false);
    if (!oldPass) { setPwError("Mevcut şifrenizi girin."); return; }
    if (!pass || pass !== confirm) { setPwError("Yeni şifreler eşleşmiyor."); return; }
    if (pass.length < 6) { setPwError("Yeni şifre en az 6 karakter olmalı."); return; }
    setPwBusy(true);
    try {
      const res = await fetch(`${BACKEND_URL}/api/author/change-password`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify({ eskiSifre: oldPass, yeniSifre: pass }),
      });
      const data = await res.json();
      if (!res.ok) { setPwError(data.error || "Şifre değiştirilemedi."); return; }
      setSaved(true); setOldPass(""); setPass(""); setConfirm("");
    } catch {
      setPwError("Bağlantı hatası, tekrar deneyin.");
    } finally {
      setPwBusy(false);
    }
  };
  const referralCode = `MST-${account.id}${account.name.split(" ")[0].slice(0, 3).toUpperCase()}`;
  const submitReferral = (e) => { e.preventDefault(); if (!refName.trim()) return; onRefer({ name: refName.trim(), contact: refContact.trim() }); setRefName(""); setRefContact(""); };
  const inputStyle = { padding: "9px 11px", border: `1px solid ${THEME.border}`, borderRadius: 3, fontSize: 16, boxSizing: "border-box", background: THEME.panelBgAlt, color: THEME.textLight };
  return (
    <div>
      {otherItems && otherItems.length > 0 && (
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 10 }}>DİĞER İŞLEMLER</div>
          <div style={{ background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 10, overflow: "hidden" }}>
            {otherItems.map(([key, label, icon], i) => (
              <button key={key} onClick={() => onNavigate && onNavigate(key)} style={{
                width: "100%", display: "flex", alignItems: "center", gap: 12, padding: "13px 16px",
                background: "none", border: "none", borderBottom: i < otherItems.length - 1 ? `1px solid ${THEME.divider}` : "none",
                cursor: "pointer", textAlign: "left", fontSize: 14, color: THEME.textLight, fontFamily: "inherit",
              }}>
                <span style={{ fontSize: 16 }}>{icon}</span>
                <span style={{ flex: 1 }}>{label}</span>
                <span style={{ color: THEME.textMuted }}>›</span>
              </button>
            ))}
          </div>
        </div>
      )}
      <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 10 }}>SÖZLEŞME ÖZETİ</div>
      <div style={{ background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 6, padding: "14px 16px", marginBottom: 22 }}>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13.5, padding: "6px 0", borderBottom: `1px solid ${THEME.divider}`, color: THEME.textLight }}><span style={{ color: THEME.textMuted }}>Süre</span><span>{account.contract.term}</span></div>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13.5, padding: "6px 0", borderBottom: `1px solid ${THEME.divider}`, color: THEME.textLight }}><span style={{ color: THEME.textMuted }}>Münhasırlık</span><span>{account.contract.exclusivity}</span></div>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13.5, padding: "6px 0", color: THEME.textLight }}><span style={{ color: THEME.textMuted }}>İmza tarihi</span><span>{formatDate(account.contract.signedDate)}</span></div>
      </div>

      <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 10 }}>YAZAR GETİR, KAZAN</div>
      <div style={{ background: `linear-gradient(135deg, ${THEME.headerGradA} 0%, ${THEME.headerGradB} 100%)`, borderRadius: 8, padding: "16px 18px", marginBottom: 12, color: THEME.textLight, border: `1px solid ${THEME.border}` }}>
        <div style={{ fontFamily: "'Fraunces', serif", fontSize: 15 }}>Referans Kodunuz: <span style={{ color: THEME.cyan, fontFamily: "'Space Mono', monospace" }}>{referralCode}</span></div>
        <div style={{ fontSize: 12.5, color: THEME.textMuted, marginTop: 6, lineHeight: 1.6 }}>Getirdiğiniz her yazar MST'ye katıldığında hizmet bakiyenize {tl(REFERRAL_REWARD)} yansır.</div>
      </div>
      <form onSubmit={submitReferral} style={{ background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 6, padding: 14, display: "flex", flexDirection: "column", gap: 10, marginBottom: 16 }}>
        <input value={refName} onChange={(e) => setRefName(e.target.value)} placeholder="Önereceğiniz yazarın adı" style={inputStyle} />
        <input value={refContact} onChange={(e) => setRefContact(e.target.value)} placeholder="Telefon veya e-posta" style={inputStyle} />
        <button type="submit" style={{ background: THEME.cyan, color: "#04121A", border: "none", borderRadius: 3, padding: "9px 0", fontSize: 13, cursor: "pointer", fontWeight: 600 }}>Öner</button>
      </form>
      {referrals.length > 0 && (
        <div style={{ marginBottom: 22 }}>
          {referrals.map((r) => (
            <div key={r.id} style={{ display: "flex", justifyContent: "space-between", fontSize: 13, background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 6, padding: "10px 14px", marginBottom: 6, color: THEME.textLight }}>
              <span>{r.name}</span><span style={{ color: r.status === "Beklemede" ? THEME.warn : THEME.success }}>{r.status}</span>
            </div>
          ))}
        </div>
      )}

      <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 10 }}>ŞİFRE DEĞİŞTİR</div>
      <form onSubmit={submit} style={{ background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 6, padding: 14, display: "flex", flexDirection: "column", gap: 10, marginBottom: 22 }}>
        <input type="password" value={oldPass} onChange={(e) => setOldPass(e.target.value)} placeholder="Mevcut şifre" style={inputStyle} />
        <input type="password" value={pass} onChange={(e) => setPass(e.target.value)} placeholder="Yeni şifre" style={inputStyle} />
        <input type="password" value={confirm} onChange={(e) => setConfirm(e.target.value)} placeholder="Yeni şifre (tekrar)" style={inputStyle} />
        {pwError && <div style={{ fontSize: 12.5, color: THEME.danger }}>{pwError}</div>}
        {saved && <div style={{ fontSize: 12.5, color: THEME.success }}>Şifreniz güncellendi.</div>}
        <button type="submit" disabled={pwBusy} style={{ background: THEME.cyan, color: "#04121A", border: "none", borderRadius: 3, padding: "9px 0", fontSize: 13, cursor: pwBusy ? "default" : "pointer", fontWeight: 600, opacity: pwBusy ? 0.7 : 1 }}>{pwBusy ? "Kaydediliyor..." : "Kaydet"}</button>
      </form>

      <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 10 }}>SIKÇA SORULAN SORULAR</div>
      {FAQ_ITEMS.map((f, i) => (
        <div key={i} style={{ background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 6, marginBottom: 8, padding: "12px 14px" }}>
          <button onClick={() => setOpenFaq(openFaq === i ? null : i)} style={{ width: "100%", background: "none", border: "none", padding: 0, textAlign: "left", cursor: "pointer", fontSize: 13.5, color: THEME.textLight }}>{f.q}</button>
          {openFaq === i && <div style={{ fontSize: 13, color: THEME.textMuted, marginTop: 8, lineHeight: 1.5 }}>{f.a}</div>}
        </div>
      ))}
    </div>
  );
}

