const AI_COST_ESTIMATE = 60;
const AI_MARKUP = 5;
const AI_PRICE = AI_COST_ESTIMATE * AI_MARKUP;
const AI_SUGGESTIONS = [
  "Bu hafta hangi içerikleri paylaşmalıyım?",
  "Bana bu ay için bir pazarlama programı hazırla",
  "Reklam bütçemi nasıl planlamalıyım?",
];

function AISubscribeScreen({ accountName, wallet, onSubscribe }) {
  const [error, setError] = useState("");
  const firstName = accountName.split(" ")[0];
  const roles = [
    { icon: "🎓", title: "Eğitimci", desc: "Kariyer programındaki konuları sizin durumunuza göre özetler, neyi önce öğrenmeniz gerektiğini söyler." },
    { icon: "📣", title: "Reklam Uzmanı", desc: "Bütçenizi, kampanya zamanlamanızı ve performansınızı yorumlar." },
    { icon: "📊", title: "Analiz Uzmanı", desc: "Satış ve stok verinizi okuyup neyin işe yaradığını açıklar." },
    { icon: "💼", title: "Satış Uzmanı", desc: "Platform stratejisi ve fiyatlandırma konusunda yönlendirir." },
    { icon: "🗂️", title: "Program Yöneticisi", desc: "İsteğinizde haftalık/aylık somut bir içerik ve pazarlama programı yazar." },
  ];
  const handle = () => { if (AI_PRICE > wallet.balance) { setError("Yetersiz bakiye — Mağaza veya Reklam sekmesinden ödeme bildirimi oluşturup yayınevi onayını bekleyin."); return; } onSubscribe(); };
  return (
    <div>
      <div style={{ background: `linear-gradient(135deg, ${THEME.headerGradA} 0%, ${THEME.headerGradB} 100%)`, borderRadius: 8, padding: "20px 20px 18px", marginBottom: 16, color: THEME.textLight, border: `1px solid ${THEME.cyan}` }}>
        <div style={{ fontSize: 10, letterSpacing: "0.2em", color: THEME.cyan }}>MST YAZAR DANIŞMANI</div>
        <div style={{ fontFamily: "'Fraunces', serif", fontSize: 19, marginTop: 6 }}>{firstName}, size özel bir danışman ekibiniz olsun</div>
        <div style={{ fontSize: 12.5, color: THEME.textMuted, marginTop: 6, lineHeight: 1.6 }}>Tek bir asistan, beş farklı uzmanlık alanıyla — sadece yazarlık kariyerinizle ilgili sorularda, sizi adınızla tanıyarak yanıt verir.</div>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 16 }}>
        {roles.map((r) => (
          <div key={r.title} style={{ display: "flex", gap: 12, background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 6, padding: "10px 12px" }}>
            <div style={{ fontSize: 20 }}>{r.icon}</div>
            <div>
              <div style={{ fontSize: 13.5, color: THEME.textLight, fontFamily: "'Fraunces', serif" }}>{r.title}</div>
              <div style={{ fontSize: 12, color: THEME.textMuted, marginTop: 2 }}>{r.desc}</div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ background: THEME.panelBg, border: `1px solid ${THEME.vipBorder}`, borderRadius: 6, padding: "14px 16px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 8 }}>
          <span style={{ fontFamily: "'Fraunces', serif", fontSize: 17, color: THEME.textLight }}>{tl(AI_PRICE)}</span>
          <span style={{ fontSize: 12, color: THEME.textMuted }}>/ ay</span>
        </div>
        {error && <div style={{ fontSize: 12.5, color: THEME.danger, marginBottom: 8 }}>{error}</div>}
        <button onClick={handle} style={{ width: "100%", background: THEME.vip, color: "#140A22", border: "none", borderRadius: 3, padding: "11px 0", fontSize: 13.5, cursor: "pointer", fontWeight: 600 }}>Abone Ol — {tl(AI_PRICE)}/ay</button>
        <div style={{ fontSize: 11, color: THEME.textMuted, marginTop: 8 }}>Bakiyenizden tahsil edilir, istediğiniz zaman iptal edebilirsiniz.</div>
      </div>
    </div>
  );
}

function AIAssistant({ account, token, onSubscribe }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  if (!account.aiSubscription?.active) return <AISubscribeScreen accountName={account.name} wallet={account.wallet} onSubscribe={onSubscribe} />;

  const firstName = account.name.split(" ")[0];
  const bookSummary = account.books.map((b) => `${b.title} (${b.totalSold} satış, ${getActiveStage(b.pipeline).label} aşamasında)`).join("; ") || "henüz kitap yok";

  // AI'ın reklam/satış verisini okuyup yorumlaması için gerçek özet
  const toplamSatis = account.books.reduce((a, b) => a + (b.totalSold || 0), 0);
  const toplamKazanc = account.books.reduce((a, b) => a + Math.round((b.totalSold || 0) * (b.salePrice || 0) * (account.royaltyRate || 0)), 0);
  const kamps = (account.campaigns || []).filter((c) => c.performance);
  let reklamOzet = "aktif reklam kampanyası yok";
  if (kamps.length) {
    const t = kamps.reduce((a, c) => {
      const p = c.performance;
      return {
        spend: a.spend + (p.spend ?? c.metaSpend ?? 0),
        imp: a.imp + (p.impressions ?? p.reach ?? 0),
        clicks: a.clicks + (p.clicks ?? 0),
        conv: a.conv + (p.conversions ?? 0),
      };
    }, { spend: 0, imp: 0, clicks: 0, conv: 0 });
    const roas = t.spend > 0 ? (t.conv / t.spend).toFixed(3) : "0";
    const cpc = t.clicks > 0 ? (t.spend / t.clicks).toFixed(2) : "0";
    const ctr = t.imp > 0 ? ((t.clicks / t.imp) * 100).toFixed(2) : "0";
    reklamOzet = `${kamps.length} kampanya — toplam harcama ${t.spend}₺, gösterim ${t.imp}, tıklama ${t.clicks}, reklam kaynaklı satış ${t.conv}, ROAS ${roas} (1₺ harcamaya düşen satış), tıklama başına maliyet ${cpc}₺, tıklama oranı %${ctr}`;
  }

  const send = async (text) => {
    if (!text.trim() || loading) return;
    const next = [...messages, { role: "user", content: text.trim() }];
    setMessages(next);
    setInput("");
    setLoading(true);
    setError("");
    try {
      let response;
      try {
        response = await fetch(`${BACKEND_URL}/api/author/menajer/sor`, {
          method: "POST",
          headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
          body: JSON.stringify({ soru: text.trim() }),
        });
      } catch (netErr) {
        throw new Error(`Ağ isteği başarısız oldu: ${netErr.message || netErr}`);
      }
      if (!response.ok) {
        let bodyText = "";
        try { bodyText = await response.text(); } catch (_) {}
        throw new Error(`API ${response.status} döndürdü: ${bodyText.slice(0, 300)}`);
      }
      const data = await response.json();
      setMessages([...next, { role: "assistant", content: data.cevap || "Yanıt alınamadı.", taslakTalep: data.taslakTalep || null }]);
    } catch (err) {
      setError(`Hata: ${err.message || err}`);
    } finally {
      setLoading(false);
    }
  };

  // Talebi onayla ve MST'ye ilet
  const [sendingReq, setSendingReq] = useState(false);
  const onayla = async (msgIndex, talep) => {
    if (sendingReq) return;
    setSendingReq(true);
    try {
      const res = await fetch(`${BACKEND_URL}/api/yazar-asistani/talep-onayla`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify(talep),
      });
      const data = await res.json();
      setMessages((prev) => prev.map((m, i) => i === msgIndex ? { ...m, taslakTalep: null, talepSonuc: res.ok ? (data.mesaj || "Talebiniz iletildi.") : (data.error || "Gönderilemedi.") } : m));
    } catch {
      setMessages((prev) => prev.map((m, i) => i === msgIndex ? { ...m, talepSonuc: "Sunucuya ulaşılamadı." } : m));
    } finally {
      setSendingReq(false);
    }
  };
  const vazgec = (msgIndex) => {
    setMessages((prev) => prev.map((m, i) => i === msgIndex ? { ...m, taslakTalep: null, talepSonuc: "Talep iptal edildi." } : m));
  };

  const KATEGORI_ETIKET = { sikayet: "Şikayet", destek: "Destek", reklam: "Reklam Talebi", indirim: "İndirimli Kitap", ceviri: "Çeviri Talebi" };

  return (
    <div>
      {/* Menajerden yanıt beklerken ekranı saran neon "özel alan" çerçevesi */}
      <NeonCerceve aktif={loading} />
      <div style={{ background: `linear-gradient(135deg, ${THEME.headerGradA} 0%, ${THEME.headerGradB} 100%)`, borderRadius: 8, padding: "14px 16px", marginBottom: 14, color: THEME.textLight, border: `1px solid ${THEME.cyan}` }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 34, height: 34, borderRadius: "50%", background: "radial-gradient(circle at 40% 35%,#2D6A4F,#1B4332)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 17, flexShrink: 0 }}>🤝</div>
          <div>
            <div style={{ fontFamily: "'Fraunces', serif", fontSize: 15 }}>Menajerim</div>
            <div style={{ fontSize: 10.5, color: THEME.gold, marginTop: 1 }}>7/24 destek</div>
          </div>
        </div>
        <div style={{ fontSize: 12, color: THEME.textMuted, marginTop: 10, lineHeight: 1.5 }}>Eğitimci · Reklam Uzmanı · Analiz Uzmanı · Satış Uzmanı · Program Yöneticisi — tek çatı altında. Geçmiş yazışmalarınız size daha iyi yardımcı olabilmek için saklanır.</div>
      </div>

      {messages.length === 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 14 }}>
          {AI_SUGGESTIONS.map((s) => (
            <button key={s} onClick={() => send(s)} style={{ background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 20, padding: "7px 13px", fontSize: 12.5, color: THEME.cyan, cursor: "pointer" }}>{s}</button>
          ))}
        </div>
      )}

      <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 14, paddingBottom: 4 }}>
        {messages.map((m, i) => (
          <div key={i} style={{ alignSelf: m.role === "user" ? "flex-end" : "flex-start", maxWidth: "85%", width: "fit-content" }}>
            <div style={{
              background: m.role === "user" ? THEME.cyan : THEME.panelBg,
              color: m.role === "user" ? "#04121A" : THEME.textLight,
              border: m.role === "user" ? "none" : `1px solid ${THEME.border}`,
              borderRadius: 8, padding: "10px 13px", fontSize: 13.5, lineHeight: 1.5, whiteSpace: "pre-wrap",
            }}>{m.content}</div>

            {m.taslakTalep && (
              <div style={{ marginTop: 8, background: THEME.panelBgAlt, border: `1px solid ${THEME.cyan}`, borderRadius: 8, padding: "12px 14px" }}>
                <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.cyan, marginBottom: 6 }}>{(KATEGORI_ETIKET[m.taslakTalep.kategori] || "Talep").toUpperCase()}</div>
                <div style={{ fontSize: 13.5, color: THEME.textLight, fontWeight: 600, marginBottom: 3 }}>{m.taslakTalep.konu}</div>
                <div style={{ fontSize: 12.5, color: THEME.textMuted, lineHeight: 1.5, marginBottom: 4 }}>{m.taslakTalep.detay}</div>
                {m.taslakTalep.kitap && <div style={{ fontSize: 12, color: THEME.textMuted, marginBottom: 10 }}>Kitap: {m.taslakTalep.kitap}</div>}
                <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
                  <button onClick={() => onayla(i, m.taslakTalep)} disabled={sendingReq} style={{ background: THEME.cyan, color: "#04121A", border: "none", borderRadius: 4, padding: "8px 14px", fontSize: 12.5, fontWeight: 600, cursor: sendingReq ? "default" : "pointer" }}>{sendingReq ? "Gönderiliyor…" : "✓ MST'ye İlet"}</button>
                  <button onClick={() => vazgec(i)} disabled={sendingReq} style={{ background: "transparent", color: THEME.textMuted, border: `1px solid ${THEME.border}`, borderRadius: 4, padding: "8px 14px", fontSize: 12.5, cursor: "pointer" }}>✗ Vazgeç</button>
                </div>
              </div>
            )}
            {m.talepSonuc && (
              <div style={{ marginTop: 8, fontSize: 12.5, color: THEME.success, background: THEME.panelBg, border: `1px solid ${THEME.border}`, borderRadius: 8, padding: "10px 13px" }}>{m.talepSonuc}</div>
            )}
          </div>
        ))}
        {loading && <div style={{ fontSize: 12.5, color: THEME.textMuted }}>Menajerim düşünüyor…</div>}
        {error && <div style={{ fontSize: 12.5, color: THEME.danger }}>{error}</div>}
      </div>

      <form onSubmit={(e) => { e.preventDefault(); send(input); }} style={{ display: "flex", gap: 8 }}>
        <input value={input} onChange={(e) => setInput(e.target.value)} placeholder="Sorunuzu yazın..." style={{ flex: 1, padding: "10px 12px", border: `1px solid ${THEME.border}`, borderRadius: 4, fontSize: 16, boxSizing: "border-box", background: THEME.panelBgAlt, color: THEME.textLight }} />
        <button type="submit" disabled={loading} style={{ background: THEME.cyan, color: "#04121A", border: "none", borderRadius: 4, padding: "10px 16px", fontSize: 13, cursor: loading ? "default" : "pointer", fontWeight: 600 }}>Gönder</button>
      </form>
    </div>
  );
}


function EducationSection({ unlocked, onUnlock, wallet }) {
  const [openIdx, setOpenIdx] = useState(0);
  const program = SERVICES.find((s) => s.key === "egitim-pro");
  return (
    <div>
      <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 12 }}>YAZAR KARİYER EĞİTİM PROGRAMI · {MODULES.length} BÖLÜM</div>
      {!unlocked && (
        <div style={{ background: `linear-gradient(135deg, ${THEME.headerGradA} 0%, ${THEME.headerGradB} 100%)`, borderRadius: 8, padding: "16px 18px", marginBottom: 16, color: THEME.textLight, border: `1px solid ${THEME.cyan}` }}>
          <div style={{ fontFamily: "'Fraunces', serif", fontSize: 15 }}>Tüm programa erişim</div>
          <div style={{ fontSize: 12.5, color: THEME.textMuted, marginTop: 4, marginBottom: 10, lineHeight: 1.6 }}>İlk bölüm (uygulama kullanımı) ücretsiz. Reklam stratejisi, sosyal medya, Instagram, BookTok/Bookstagram iş birliği, PR, e-posta bülteni ve kitap lansmanı planlaması dahil kalan {MODULES.length - 1} bölüm için tek seferlik {tl(program.price)}.</div>
          <button onClick={onUnlock} style={{ background: THEME.cyan, color: "#04121A", border: "none", borderRadius: 3, padding: "9px 16px", fontSize: 13, cursor: "pointer", fontWeight: 600 }}>Programı Satın Al — {tl(program.price)}</button>
        </div>
      )}
      {MODULES.map((m, i) => {
        const locked = !m.free && !unlocked;
        const open = openIdx === i && !locked;
        return (
          <div key={i} style={{ borderRadius: 8, overflow: "hidden", marginBottom: 14, border: `1px solid ${THEME.border}`, opacity: locked ? 0.6 : 1, boxShadow: "0 4px 14px rgba(0,0,0,0.35)" }}>
            {locked ? (
              <div style={{ padding: "18px 20px", background: m.color, color: THEME.textLight, display: "flex", alignItems: "center", gap: 14 }}>
                <FilmFrameIcon glyph="🔒" tint={m.color} />
                <div>
                  <div style={{ fontSize: 10, letterSpacing: "0.18em", color: "rgba(231,236,255,0.55)" }}>BÖLÜM {i + 1} · PROGRAM GEREKLİ</div>
                  <div style={{ fontFamily: "'Fraunces', serif", fontSize: 15.5, marginTop: 2 }}>{m.title}</div>
                </div>
              </div>
            ) : (
              <CinematicHeader module={m} openable onClick={() => setOpenIdx(open ? -1 : i)} />
            )}
            {open && (
              <div style={{ background: THEME.panelBg, padding: "16px 18px" }}>
                {m.steps ? (
                  <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                    {m.steps.map((s, j) => (
                      <div key={j} style={{ display: "flex", gap: 12 }}>
                        <FilmFrameIcon glyph={j + 1} tint={s.tint} />
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 10, letterSpacing: "0.1em", color: THEME.textMuted, marginBottom: 2 }}>{s.tag.toUpperCase()}</div>
                          <div style={{ fontSize: 14, color: THEME.textLight, fontFamily: "'Fraunces', serif", marginBottom: 4 }}>{s.title}</div>
                          <div style={{ fontSize: 13, color: THEME.textMuted, lineHeight: 1.6 }}>{s.detail}</div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                    {m.body.map((p, j) => <div key={j} style={{ fontSize: 13.5, color: THEME.textLight, lineHeight: 1.6 }}>{p}</div>)}
                  </div>
                )}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

export default function App() {
  const [session, setSession] = useState(null);
  const [authorsData, setAuthorsData] = useState(AUTHORS_SEED);
  const [supportData, setSupportData] = useState(SUPPORT_SEED);
  const [submissionData, setSubmissionData] = useState(SUBMISSIONS_SEED);
  const [referralData, setReferralData] = useState({ 1: [], 2: [], 3: [] });
  const [expandedId, setExpandedId] = useState(null);
  const [tab, setTab] = useState("stok");
  const [wcProducts, setWcProducts] = useState([]);
  const [wcLoading, setWcLoading] = useState(false);

  // NOT: Kitaplar artık yazarın kendi hesabından (account.books) gösterilir.
  // Eski /api/products çağrısı tüm mağazayı çekiyordu (her yazara herkesin kitabı görünüyordu) — kaldırıldı.

  React.useEffect(() => {
    let meta = document.querySelector('meta[name="viewport"]');
    if (!meta) {
      meta = document.createElement("meta");
      meta.name = "viewport";
      document.head.appendChild(meta);
    }
    meta.setAttribute("content", "width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no, viewport-fit=cover");

    const styleId = "mst-app-shell-style";
    if (!document.getElementById(styleId)) {
      const style = document.createElement("style");
      style.id = styleId;
      style.textContent = `
        @import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Fraunces:opsz,wght@9..144,500;9..144,600;9..144,700&family=Space+Mono:wght@400;700&display=swap');
        html, body { touch-action: manipulation; -webkit-text-size-adjust: 100%; overscroll-behavior: none; margin: 0; background: ${THEME.bg}; }
        * { -webkit-tap-highlight-color: transparent; }
        input, textarea, select, button { touch-action: manipulation; }
        ::selection { background: rgba(45,106,79,0.3); }
        @keyframes mstScan { 0% { transform: translateY(-100%); opacity:0; } 8% { opacity:.5; } 92% { opacity:.5; } 100% { transform: translateY(720px); opacity:0; } }
      `;
      document.head.appendChild(style);
    }
  }, []);

  const [oyun, setOyun] = useState(null);
  const [aktifKutlamalar, setAktifKutlamalar] = useState([]);
  const [katman, setKatman] = useState(null);
  const [myAnnouncements, setMyAnnouncements] = useState([]);

  // Oyunlaştırma durumu (XP, seviye, görevler, ödüller, başarımlar, dükkan, kutlamalar)
  const oyunCek = React.useCallback(async () => {
    if (!session) return;
    try {
      const res = await fetch(`${BACKEND_URL}/api/author/oyun`, { headers: { Authorization: `Bearer ${session.token}` } });
      const data = await res.json();
      if (data && !data.error) {
        setOyun(data);
        if (data.kutlamalar && data.kutlamalar.length) setAktifKutlamalar(data.kutlamalar);
      }
    } catch { /* sessiz */ }
  }, [session]);
  React.useEffect(() => { oyunCek(); }, [oyunCek]);

  // Katmanlı mimari: giriş kaydı (seri) + durum çek
  React.useEffect(() => {
    if (!session) return;
    // Giriş kaydı yap (seri güncellenir), sonra durum çek
    fetch(`${BACKEND_URL}/api/author/katman/giris`, { headers: { Authorization: `Bearer ${session.token}` } })
      .catch(() => {})
      .finally(() => {
        fetch(`${BACKEND_URL}/api/author/katman/durum`, { headers: { Authorization: `Bearer ${session.token}` } })
          .then((r) => r.json()).then((d) => { if (d && !d.error) setKatman(d); }).catch(() => {});
      });
  }, [session]);

  const authFetch = (path, options = {}) => fetch(`${BACKEND_URL}${path}`, {
    ...options,
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${session?.token}`, ...(options.headers || {}) },
  });

  // Duyuruları backend'den yükle (admin panelinden yayınlananlar)
  React.useEffect(() => {
    if (!session) return;
    authFetch("/api/author/announcements")
      .then((r) => r.json())
      .then((d) => setMyAnnouncements((d.announcements || []).map((a) => ({
        id: a.id, title: a.baslik, body: a.icerik,
        date: a.created_at ? formatDate(String(a.created_at).slice(0, 10)) : "",
      }))))
      .catch(() => {});
  }, [session]); // eslint-disable-line

  if (!session) return <LoginScreen onLogin={setSession} />;
  const account = session.account;
  const vip = account.plan === "vip";

  // ONBOARDING KAPISI: yazarın hiçbir kitabı "yayin" aşamasında değilse
  // (henüz hiç kitabı olmayan yeni yazar dahil) tam uygulama yerine süreç/bekleme ekranı gösterilir.
  const yayindaKitapVar = (account.books || []).some((b) => b.pipeline && isPublished(b.pipeline));
  if (!yayindaKitapVar) {
    return <OnboardingScreen account={account} token={session.token} onLogout={() => setSession(null)} />;
  }

  const kutlamaKapat = async (ids) => {
    setAktifKutlamalar([]);
    try {
      await fetch(`${BACKEND_URL}/api/author/oyun/kutlama-gosterildi`, {
        method: "POST", headers: { Authorization: `Bearer ${session.token}`, "Content-Type": "application/json" },
        body: JSON.stringify({ ids }),
      });
    } catch { /* sessiz */ }
  };
  const myRequests = supportData[account.id] || [];
  const myAdRequests = account.adRequests || [];
  const myCampaigns = account.campaigns || [];
  const myTranslations = account.translationRequests || [];
  const myNotices = (account.wallet.pendingReceipts || []).map((r) => ({
    id: r.id, amount: Number(r.amount), date: formatDate(r.created_at ? String(r.created_at).slice(0, 10) : null),
    status: r.status === "bekliyor" ? "Onay bekliyor" : r.status === "onaylandi" ? "Onaylandı" : "Reddedildi",
  }));
  const myOrders = account.serviceOrders || [];
  const mySubmissions = submissionData[account.id] || [];
  const myReferrals = referralData[account.id] || [];

  const refreshAccount = async () => {
    try {
      const res = await fetch(`${BACKEND_URL}/api/author/me`, {
        headers: { Authorization: `Bearer ${session.token}` },
      });
      const data = await res.json();
      if (data.account) setSession((prev) => ({ ...prev, account: data.account }));
    } catch {
      // sessiz geç — bir sonraki işlemde tekrar denenir
    }
  };

  const approveCover = (bookId) => {
    setSession((prev) => {
      const acc = { ...prev.account };
      acc.books = acc.books.map((b) => {
        if (b.id !== bookId) return b;
        const pipeline = b.pipeline.map((s) => (s.key === "kapak" ? { ...s, approved: true, status: "tamamlandi" } : s));
        const idx = pipeline.findIndex((s) => s.key === "kapak");
        if (pipeline[idx + 1] && pipeline[idx + 1].status === "beklemede") pipeline[idx + 1] = { ...pipeline[idx + 1], status: "devam" };
        return { ...b, pipeline };
      });
      return { ...prev, account: acc };
    });
  };
  const submitRequest = async ({ subject, message, kategori }) => {
    try {
      const res = await authFetch("/api/author/destek", { method: "POST", body: JSON.stringify({ konu: subject, mesaj: message, kategori: kategori || "destek" }) });
      if (res.ok) {
        // İyimser güncelleme: hemen listede göster
        setSupportData((prev) => ({ ...prev, [account.id]: [{ id: Date.now(), date: "Bugün", subject, message, status: "açık", reply: null }, ...(prev[account.id] || [])] }));
      } else {
        alert((await res.json()).error || "Talep gönderilemedi");
      }
    } catch { alert("Sunucuya bağlanılamadı."); }
  };

  const submitAdRequest = async ({ bookTitle, budget, note }) => {
    const res = await authFetch("/api/author/ad-request", { method: "POST", body: JSON.stringify({ bookTitle, budget, note }) });
    if (res.ok) refreshAccount(); else alert((await res.json()).error || "Talep gönderilemedi");
  };
  const submitTranslation = async ({ bookId, bookTitle, language }) => {
    const res = await authFetch("/api/author/translation-request", { method: "POST", body: JSON.stringify({ bookId, bookTitle, language }) });
    if (res.ok) refreshAccount(); else alert((await res.json()).error || "Talep gönderilemedi");
  };
  const submitNotice = async ({ amount, note }) => {
    const res = await authFetch("/api/author/payment-receipt", { method: "POST", body: JSON.stringify({ amount, note }) });
    if (res.ok) refreshAccount(); else alert((await res.json()).error || "Bildirim gönderilemedi");
  };
  const startCampaign = async ({ bookTitle, platform, budget, duration }) => {
    const res = await authFetch("/api/author/ad-campaign", { method: "POST", body: JSON.stringify({ bookTitle, platform, budget, duration }) });
    if (res.ok) refreshAccount(); else alert((await res.json()).error || "Kampanya başlatılamadı");
  };
  const placeOrder = async ({ serviceKey, title, bookTitle, detail, price, status }) => {
    const res = await authFetch("/api/author/service-order", { method: "POST", body: JSON.stringify({ serviceKey, title, bookTitle, detail, price, status }) });
    if (res.ok) refreshAccount(); else alert((await res.json()).error || "Sipariş oluşturulamadı");
  };
  const unlockEgitimDirect = () => placeOrder({ serviceKey: "egitim-pro", title: "Yazar Kariyer Eğitim Programı", price: SERVICES.find((s) => s.key === "egitim-pro").price, status: "Onay bekliyor" });
  const subscribeAI = async () => {
    const res = await authFetch("/api/author/ai-subscribe", { method: "POST", body: JSON.stringify({ price: AI_PRICE }) });
    if (res.ok) refreshAccount(); else alert((await res.json()).error || "Abonelik başlatılamadı");
  };
  const submitNewBook = ({ title, pages, note, file }) => setSubmissionData((prev) => ({ ...prev, [account.id]: [{ id: Date.now(), title, pages, note, file: file ? file.name : null, status: "İnceleniyor" }, ...(prev[account.id] || [])] }));
  const submitReferral = ({ name, contact }) => setReferralData((prev) => ({ ...prev, [account.id]: [{ id: Date.now(), name, contact, status: "Beklemede" }, ...(prev[account.id] || [])] }));

  const tabs = [["kitaplar", "Kitaplarım"], ["stok", "Stok Takip"], ["kariyer", "Kariyer & Görevler"], ["magaza", "Mağaza"], ["reklam", "Reklam"], ...(vip ? [["ek", "Ek Hizmetler"]] : []), ["kazanc", "Kazanç"], ["egitim", "Eğitim"], ["ai", "Yazar Danışmanım"], ["destek", "Duyuru & Destek"], ["hesabim", "Hesabım"]];
  const OTHER_ITEMS = [["kariyer", "Kariyer & Görevler", "🌱"], ["magaza", "Mağaza", "🛍️"], ["reklam", "Reklam", "📣"], ...(vip ? [["ek", "Ek Hizmetler", "✨"]] : []), ["egitim", "Eğitim", "🎓"], ["destek", "Duyuru & Destek", "🔔"]];
  const BOTTOM_NAV = [
    { key: "stok", label: "Pano", icon: "◎" },
    { key: "kitaplar", label: "Kitaplar", icon: "📖" },
    { key: "ai", label: "Menajerim", icon: "🤝", center: true },
    { key: "kazanc", label: "Kazanç", icon: "💰" },
    { key: "hesabim", label: "Profil", icon: "👤" },
  ];

  return (
    <div style={{ position: "fixed", inset: 0, overflowY: "auto", background: THEME.bg, fontFamily: "'Manrope', sans-serif" }}>
      {aktifKutlamalar.length > 0 && <KutlamaOverlay kutlamalar={aktifKutlamalar} onKapat={kutlamaKapat} />}
      <GridBackdrop />
      <ScanLine />
      <div style={{ position: "relative", zIndex: 2 }}>
      <div style={{ background: THEME.headerBg, padding: "22px 18px 14px", color: THEME.textLight, borderBottom: `1px solid ${THEME.border}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <img src={LOGO_HEADER} alt="MST" style={{ width: 34, height: "auto", flexShrink: 0 }} />
            <div>
              <div style={{ fontFamily: "'Fraunces', serif", fontWeight: 700, fontSize: 15, color: THEME.cyan, letterSpacing: "0.03em" }}>MST YAYINCILIK</div>
              <div style={{ fontSize: 8.5, letterSpacing: "0.18em", color: THEME.gold, marginTop: 1 }}>YAZAR ASİSTANINIZ</div>
            </div>
            <div style={{ marginLeft: 4 }}><PlanBadge plan={account.plan} /></div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <NotificationBell account={account} />
            <button onClick={() => setSession(null)} style={{ background: "none", border: `1px solid ${THEME.border}`, color: THEME.cyan, fontSize: 11, borderRadius: 3, padding: "5px 10px", cursor: "pointer" }}>ÇIKIŞ</button>
          </div>
        </div>
      </div>
      <div style={{ padding: "18px 14px 110px" }}>
        {tab === "kitaplar" && (<>
          <div style={{ fontSize: 11, letterSpacing: "0.05em", color: THEME.textMuted, marginBottom: 10 }}>
            KİTAPLARINIZ ({account.books.length})
          </div>
          <NewBookForm onSubmit={submitNewBook} submissions={mySubmissions} />
          {account.books.map((b) => <BookCard key={b.id} book={b} plan={account.plan} expanded={expandedId === b.id} onToggle={() => setExpandedId(expandedId === b.id ? null : b.id)} onApproveCover={approveCover} />)}
          <div style={{ marginTop: 8, fontSize: 11.5, color: THEME.textMuted, textAlign: "center", lineHeight: 1.6 }}>
            Stok ve satış verileri Trendyol, N11, Hepsiburada ve Pazarama satıcı panellerinden senkronize edilir.
          </div>
        </>)}
        {tab === "stok" && <StockOrbitTab books={account.books} account={account} token={session.token} onQuickAction={(t) => setTab(t)} />}
        {tab === "kariyer" && <GameSection oyun={oyun} token={session.token} onRefresh={oyunCek} katman={katman} />}
        {tab === "magaza" && <StoreSection plan={account.plan} books={account.books} wallet={account.wallet} notices={myNotices} orders={myOrders} onOrder={placeOrder} onSubmitNotice={submitNotice} token={session.token} />}
        {tab === "reklam" && <AdSection plan={account.plan} books={account.books} wallet={account.wallet} adRequests={myAdRequests} campaigns={myCampaigns} onSubmitRequest={submitAdRequest} onStartCampaign={startCampaign} />}
        {tab === "ek" && vip && <ExtrasSection books={account.books} requests={myTranslations} onSubmit={submitTranslation} />}
        {tab === "kazanc" && <EarningsSection account={account} />}
        {tab === "egitim" && <EducationSection unlocked={account.unlocked["egitim-pro"]} onUnlock={unlockEgitimDirect} wallet={account.wallet} />}
        {tab === "ai" && <AIAssistant account={account} token={session.token} onSubscribe={subscribeAI} />}
        {tab === "destek" && (<><Announcements items={myAnnouncements} /><SupportSection requests={myRequests} onSubmit={submitRequest} /></>)}
        {tab === "hesabim" && <AccountSection account={account} token={session.token} referrals={myReferrals} onRefer={submitReferral} otherItems={OTHER_ITEMS} onNavigate={setTab} />}
      </div>
      </div>

      {/* Alt navigasyon — referans tasarıma göre 5 slot + ortada öne çıkan amblem */}
      <div style={{ position: "fixed", left: 0, right: 0, bottom: 0, zIndex: 10, display: "flex", justifyContent: "center", padding: "0 14px 18px" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", width: "100%", maxWidth: 420, background: THEME.cyanDim, borderRadius: 26, padding: "10px 16px", boxShadow: "0 10px 28px rgba(22,56,38,0.35)" }}>
          {BOTTOM_NAV.map((item) =>
            item.center ? (
              <button key={item.key} onClick={() => setTab(item.key)} style={{
                position: "relative", width: 58, height: 58, marginTop: -32,
                background: "none", border: "none", cursor: "pointer",
                display: "flex", alignItems: "center", justifyContent: "center",
              }}>
                <style>{`
                  @keyframes mgrBtnBreath { 0%,100% { transform: scale(1); box-shadow: 0 6px 18px rgba(201,162,39,.45), 0 0 0 rgba(201,162,39,0); } 50% { transform: scale(1.05); box-shadow: 0 8px 24px rgba(201,162,39,.6), 0 0 16px rgba(201,162,39,.35); } }
                  @keyframes mgrBtnRing { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
                  @keyframes mgrBtnRingRev { from { transform: rotate(360deg); } to { transform: rotate(0deg); } }
                  .mgr-btn-core { animation: mgrBtnBreath 3.2s ease-in-out infinite; }
                  .mgr-btn-ring { position: absolute; inset: -3px; border-radius: 50%; border: 1.5px solid transparent; border-top-color: ${THEME.gold}; border-right-color: rgba(201,162,39,.3); animation: mgrBtnRing 4s linear infinite; }
                  .mgr-btn-ring2 { position: absolute; inset: -6px; border-radius: 50%; border: 1px solid transparent; border-bottom-color: rgba(124,231,255,.5); animation: mgrBtnRingRev 6s linear infinite; }
                `}</style>
                <span className="mgr-btn-ring" />
                <span className="mgr-btn-ring2" />
                <span className="mgr-btn-core" style={{
                  width: 54, height: 54, borderRadius: "50%",
                  background: "radial-gradient(circle at 40% 35%, #3d8063, #1B4332)", border: `2px solid ${THEME.gold}`,
                  display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24,
                }}>
                  🤝
                </span>
              </button>
            ) : (
              <button key={item.key} onClick={() => setTab(item.key)} style={{
                background: "none", border: "none", cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 3,
                color: tab === item.key ? THEME.gold : "rgba(247,244,236,0.55)",
              }}>
                <span style={{ fontSize: 17 }}>{item.icon}</span>
                <span style={{ fontSize: 9.5, fontWeight: 600 }}>{item.label}</span>
              </button>
            )
          )}
        </div>
      </div>
    </div>
  );
}
